const j = $json || {};
let raw = '';
if (j.message && j.message.content) raw = j.message.content;
else if (j.content && j.content[0] && j.content[0].text) raw = j.content[0].text;
let data = null;
try { data = JSON.parse(raw.replace(/^```(?:json)?\s*/i,'').replace(/\s*```$/i,'')); }
catch (e) { try { const m = raw.match(/\{[\s\S]*\}/); if (m) data = JSON.parse(m[0]); } catch (e2) { data = null; } }
const r = $('Resolve Input').first().json;
return [{ json: { data: data, topic: r.topic, date: r.date, client: r.client, markdown: raw } }];

/* --- Jarvis brand kit (shared across awareness PDFs): avatar + takeaways box + sign-off --- */
var __jfs=null; try{__jfs=require('fs');}catch(e){}
function jAvatarUri(){ if(!__jfs) return ''; var t=[['/config/branding/jarvis-avatar.png','image/png'],['/config/branding/jarvis-avatar.jpg','image/jpeg'],['/config/branding/jarvis-avatar.jpeg','image/jpeg'],['/config/branding/jarvis-avatar.svg','image/svg+xml']]; for(var i=0;i<t.length;i++){ try{ return 'data:'+t[i][1]+';base64,'+__jfs.readFileSync(t[i][0]).toString('base64'); }catch(e){} } return ''; }
var JKIT_SVG='<svg class="jav" viewBox="0 0 64 64" xmlns="http://www.w3.org/2000/svg"><defs><linearGradient id="jkitg" x1="0" y1="0" x2="0" y2="1"><stop offset="0" stop-color="#0E7C86"/><stop offset="1" stop-color="#0A1A2F"/></linearGradient></defs><circle cx="32" cy="32" r="32" fill="url(#jkitg)"/><rect x="19" y="21" width="26" height="22" rx="7" fill="#fff"/><circle cx="27" cy="32" r="3.2" fill="#0E7C86"/><circle cx="37" cy="32" r="3.2" fill="#0E7C86"/><rect x="27" y="38" width="10" height="2.4" rx="1.2" fill="#0E7C86"/><rect x="30.7" y="14" width="2.6" height="6" rx="1.3" fill="#9fe4d8"/><circle cx="32" cy="13" r="2.4" fill="#E7C76A"/><path d="M23 47h18l-3 4.5H26z" fill="#9fe4d8"/></svg>';
var JKIT_CSS=".jkit-take{background:#F4F6F9;border:1px solid #E2E6EC;border-left:4px solid #0E7C86;border-radius:10px;padding:14px 18px;margin:22px 0 0;page-break-inside:avoid}.jkit-take .th{font-family:-apple-system,'Segoe UI',Arial,sans-serif;font-size:11px;letter-spacing:2px;text-transform:uppercase;color:#0A1A2F;font-weight:800;margin:0 0 7px}.jkit-take ul{margin:0;padding-left:18px}.jkit-take li{font-size:13.5px;line-height:1.5;color:#2b3340;margin:5px 0}.jkit-sign{display:flex;align-items:center;gap:12px;margin:20px 0 0;padding-top:14px;border-top:2px solid #0E7C86;page-break-inside:avoid}.jkit-sign img,.jkit-sign .jav{width:46px;height:46px;border-radius:50%;border:2px solid #0E7C86;flex:0 0 auto}.jkit-sign .nm{font-family:Georgia,serif;font-size:15px;color:#0A1A2F;font-weight:700}.jkit-sign .rl{font-family:-apple-system,'Segoe UI',Arial,sans-serif;font-size:10px;letter-spacing:2px;text-transform:uppercase;color:#0E7C86;font-weight:800;margin-top:2px}";
function jKitEsc(s){ return (s==null?'':String(s)).replace(/[&<>]/g,function(c){return({'&':'&amp;','<':'&lt;','>':'&gt;'})[c];}); }
function jTakeBox(takeaways){ var t=(takeaways||[]).filter(Boolean).slice(0,4); if(!t.length) return ''; return '<div class="jkit-take"><div class="th">Key takeaways &middot; Lessons learned</div><ul>'+t.map(function(x){return '<li>'+jKitEsc(x)+'</li>';}).join('')+'</ul></div>'; }
function jSignoff(){ var av=jAvatarUri(); var avatar=av?('<img src="'+av+'"/>'):JKIT_SVG; return '<div class="jkit-sign">'+avatar+'<div><div class="nm">Jarvis</div><div class="rl">Your AI Awareness Assistant</div></div></div>'; }
function jKitBlock(takeaways){ return jTakeBox(takeaways)+jSignoff(); }

const d=$json.data||{}; const topic=$json.topic||'Incident'; const date=$json.date||''; const client=($json.client||'').toString();
function esc(s){ return (s==null?'':String(s)).replace(/[&<>]/g,function(c){return({'&':'&amp;','<':'&lt;','>':'&gt;'})[c];}); }
// Hero image arrives as an on-disk path (Generate Image) — inline only at render time.
function imgSrc(p){ if(!p) return ''; var s=String(p); if(s.indexOf('data:')===0) return s; if(__jfs){ try{ return 'data:image/png;base64,'+__jfs.readFileSync(s).toString('base64'); }catch(e){} } return ''; }
const hero = imgSrc($json.imageFile);
const byline=client?('Prepared for '+client):'Security Awareness';
const AV = jAvatarUri(); const AVATAR = AV?('<img src="'+AV+'"/>'):JKIT_SVG;
function ul(a){ return '<ul>'+((a||[]).map(function(x){return '<li>'+esc(x)+'</li>';}).join(''))+'</ul>'; }
var roles=((d.roles||[]).map(function(r){return '<tr><td class="rl">'+esc(r.role)+'</td><td>'+esc(r.brief)+'</td></tr>';}).join(''));
var injects=((d.injects||[]).map(function(x,i){return '<div class="card"><span class="pill">'+esc(x.time||('Inject '+(i+1)))+'</span><p style="margin:8px 0 6px"><b>'+esc(x.inject)+'</b></p><p style="margin:0;color:#0E7C86"><b>Discuss:</b> '+esc(x.prompt)+'</p></div>';}).join(''));

// Footer lives in the @page bottom margin (reserved below), so content never runs
// under it — fixes the previous overlap from a fixed footer with margin:0 pages.
var CSS="@page{size:A4;margin:16mm 15mm 18mm} *{box-sizing:border-box} body{margin:0;font-family:-apple-system,\"Segoe UI\",Arial,sans-serif;color:#11151c}"
+".band{background:linear-gradient(120deg,#0A1A2F,#0E7C86);color:#fff;border-radius:12px;padding:16px 20px;display:flex;align-items:center;justify-content:space-between;gap:14px}"
+".band .kick{font-size:11px;letter-spacing:3px;text-transform:uppercase;color:#E7C76A;font-weight:800}"
+".band h1{font-family:Georgia,serif;font-size:25px;margin:4px 0 0;font-weight:800;line-height:1.1}"
+".band .sub{font-size:11.5px;color:#cfe0e6;margin-top:5px}"
+".band .av img,.band .av .jav{width:46px;height:46px;border-radius:50%;border:2px solid #9fe4d8;flex:0 0 auto}"
+".hero{width:100%;height:62mm;object-fit:cover;border-radius:12px;margin:14px 0 4px;display:block;border:1px solid #E2E6EC}"
+"h2{font-family:Georgia,serif;font-size:18px;color:#0E2233;margin:20px 0 9px;border-bottom:2px solid #0E7C86;padding-bottom:6px;page-break-after:avoid}"
+"p{font-size:13.5px;line-height:1.6;color:#2b3340} .lead{font-size:14.5px;color:#1E2A33}"
+".foot{position:fixed;left:15mm;right:15mm;bottom:8mm;color:#9aa6b2;font-size:10px;border-top:1px solid #E2E6EC;padding-top:6px;display:flex;justify-content:space-between}"
+".card{border:1px solid #E2E6EC;border-left:4px solid #0E7C86;border-radius:8px;padding:12px 15px;margin:10px 0;page-break-inside:avoid}"
+".pill{display:inline-block;background:#E6F4F1;color:#0E7C86;font-weight:800;font-size:11px;padding:3px 10px;border-radius:12px;letter-spacing:.5px}"
+"table.r{width:100%;border-collapse:collapse;margin:6px 0} table.r td{border:1px solid #E2E6EC;padding:8px 10px;font-size:13px;vertical-align:top} table.r tr{page-break-inside:avoid} table.r td.rl{font-weight:700;color:#0E2233;width:30%}"
+"ul{margin:6px 0;padding-left:20px} li{font-size:13.5px;line-height:1.55;margin:5px 0;color:#2b3340}"
+".sec{page-break-inside:avoid}"+JKIT_CSS;

var body=''
 +'<div class="band"><div><div class="kick">Tabletop Exercise · Facilitator pack</div><h1>'+esc(d.title||(topic+' — Tabletop Exercise'))+'</h1><div class="sub">'+esc(byline)+' · ~45 minutes</div></div><span class="av">'+AVATAR+'</span></div>'
 +(hero?('<img class="hero" src="'+hero+'" alt="">'):'')
 +'<div class="sec"><h2>Scenario</h2><p class="lead">'+esc(d.scenario||'')+'</p></div>'
 +'<div class="sec"><h2>Objectives</h2>'+ul(d.objectives)+'</div>'
 +'<div class="sec"><h2>Roles</h2><table class="r">'+roles+'</table></div>'
 +'<h2>Injects</h2>'+injects
 +'<div class="sec"><h2>Debrief questions</h2>'+ul(d.debrief)+'</div>'
 +'<div class="sec"><h2>Facilitator notes</h2>'+ul(d.facilitatorNotes)+'</div>'
 +jKitBlock(d.takeaways||d.keyLessons)
 +'<div class="foot"><span>'+esc(byline)+' · AI-generated — review before use</span><span>'+esc(date)+'</span></div>';
const html='<!doctype html><html><head><meta charset="utf-8"><style>'+CSS+'</style></head><body>'+body+'</body></html>';
// Hero is baked into the HTML now — clean the temp work dir (guard: /.work/).
if ($json.workDir && String($json.workDir).indexOf('/.work/')>=0 && __jfs) { try { __jfs.rmSync($json.workDir,{recursive:true,force:true}); } catch(e){} }
const fileSafe=topic.toLowerCase().replace(/[^a-z0-9]+/g,'-').replace(/^-|-$/g,'').slice(0,40)||'tabletop';
return [{ json:{ html:html, topic:topic, date:date, fileSafe:fileSafe, outDir:'tabletop', filePrefix:'tabletop' } }];

const html = $json.html || '';
return [{ json: { topic:$json.topic, date:$json.date, fileSafe:$json.fileSafe, outDir:$json.outDir, filePrefix:$json.filePrefix },
  binary: { data: { data: Buffer.from(html,'utf8').toString('base64'), mimeType:'text/html', fileName:'index.html' } } }];

const fs = require('fs');
const meta = $('Render HTML').first().json;
const dir = '/reports/awareness/' + (meta.outDir || 'misc');
const name = (meta.filePrefix || 'asset') + '-' + (meta.fileSafe || 'item') + '-' + meta.date + '.pdf';
let buf = null;
try { buf = await this.helpers.getBinaryDataBuffer(0, 'data'); } catch (e) {}
try { fs.mkdirSync(dir, { recursive: true }); if (buf) fs.writeFileSync(dir + '/' + name, buf); } catch (e) {}
const out = { json: { ok: !!buf, file: dir + '/' + name, topic: meta.topic } };
try { const b = $input.first().binary; if (b && b.data) { b.data.fileName = name; out.binary = { data: b.data }; } } catch (e) {}
return [out];

// Generate ONE header image for the tabletop pack with the shared image provider
// (gpt-image-2). Written to a temp work dir on disk; only the file path is returned
// in JSON (never base64). Graceful: on any failure the render simply omits the hero.
const fs = require('fs');
const H = this.helpers;
const j = $json || {};
const d = j.data || {};
const topic = j.topic || 'incident response';
const key = $env.OPENAI_IMAGE_API_KEY || $env.OPENAI_API_KEY;
const want = (($env.TABLETOP_IMAGE || $env.CYBER_SECTION_IMAGES || 'true').toString().toLowerCase() !== 'false');
const baseu = ($env.OPENAI_BASE_URL || 'https://api.openai.com/v1');
const model = ($env.IMAGE_MODEL || 'gpt-image-1');
const QV = { low:1, medium:1, high:1, auto:1 };
let quality = String($env.TABLETOP_IMAGE_QUALITY || $env.COMIC_IMAGE_QUALITY || 'medium').toLowerCase(); if (!QV[quality]) quality = 'medium';
let timeout = parseInt($env.IMAGE_TIMEOUT || '120000', 10); if (!(timeout > 0)) timeout = 120000;

const baseName = (topic.toLowerCase().replace(/[^a-z0-9]+/g,'-').replace(/^-|-$/g,'').slice(0,40) || 'tabletop') + '-' + (j.date || new Date().toISOString().slice(0,10));
const workDir = '/reports/awareness/tabletop/.work/' + baseName;
try { fs.mkdirSync(workDir, { recursive: true }); } catch (e) {}

const prompt = 'Cinematic, semi-realistic editorial illustration for a corporate cyber crisis-management TABLETOP EXERCISE about ' + topic + '. '
  + (d.scenario ? ('Scene: ' + String(d.scenario).slice(0, 300) + '. ') : '')
  + 'A calm, focused incident-response / war-room atmosphere, diverse professionals around a table with screens, modern office, dramatic but professional lighting, teal and deep-navy colour grade, wide 16:9 composition. '
  + 'No text, no words, no letters, no logos, no watermark, no charts, no UI.';

let imageFile = '';
if (want && key) {
  try {
    const resp = await H.httpRequest({ method: 'POST', url: baseu + '/images/generations',
      headers: { Authorization: 'Bearer ' + key, 'Content-Type': 'application/json' },
      body: { model: model, prompt: prompt, size: '1536x1024', quality: quality, n: 1 }, json: true, timeout: timeout });
    const b64 = resp && resp.data && resp.data[0] && resp.data[0].b64_json;
    if (b64) { imageFile = workDir + '/header.png'; fs.writeFileSync(imageFile, Buffer.from(b64, 'base64')); }
  } catch (e) { imageFile = ''; }
}

return [{ json: Object.assign({}, j, { imageFile: imageFile, workDir: workDir }) }];
